  9вҶ’  ruleEffectSchema,
 10вҶ’  ruleSelectorSchema,
 11вҶ’} from "@chat-exporter/shared";
 12вҶ’
 13вҶ’import { blockToPlainText } from "./reader-block-render";
 14вҶ’import { matchesReaderRule, type ReaderMatchContext } from "./rule-matching";
 15вҶ’
 16вҶ’// Re-exports for backward compatibility
 17вҶ’export {
 18вҶ’  blockToPlainText,
 19вҶ’  collectInserts,
 20вҶ’  getReaderBlockClassName,
 21вҶ’  getReaderBlockStyle,
