 23вҶ’} from "./reader-block-render";
 24вҶ’export { getBlocksMatchingRule } from "./rule-matching";
 25вҶ’
 26вҶ’export function resolveReaderBlockEffects(
 27вҶ’  rules: FormatRule[],
 28вҶ’  messageId: string,
 29вҶ’  blockIndex: number,
 30вҶ’  blockType: Block["type"],
 31вҶ’  blockText: string,
 32вҶ’  context?: ReaderMatchContext,
 33вҶ’) {
 34вҶ’  return rules
 35вҶ’    .filter(
 36вҶ’      (rule) =>
 37вҶ’        rule.status === "active" &&
 38вҶ’        matchesReaderRule(
 39вҶ’          rule,
 40вҶ’          messageId,
 41вҶ’          blockIndex,
 42вҶ’          blockType,
 43вҶ’          blockText,
 44вҶ’          context,
 45вҶ’        ),
 46вҶ’    )
 47вҶ’    .map((rule) => rule.compiledRule)
 48вҶ’    .filter((effect): effect is RuleEffect => effect !== undefined)
 49вҶ’    .map(normalizeLegacyEffect);
 50вҶ’}
 51вҶ’
 52вҶ’export function buildReaderEffectsMap(
 53вҶ’  rules: FormatRule[],
 54вҶ’  conversation: Conversation,
 55вҶ’): Map<string, RuleEffect[]> {
 56вҶ’  const activeRules = rules.filter((r) => r.status === "active");
 57вҶ’  const effectsMap = new Map<string, RuleEffect[]>();
 58вҶ’
 59вҶ’  for (const message of conversation.messages) {
 60вҶ’    const context: ReaderMatchContext = {
 61вҶ’      messageRole: message.role,
 62вҶ’      blocks: message.blocks,
 63вҶ’    };
 64вҶ’
 65вҶ’    for (
 66вҶ’      let blockIndex = 0;
 67вҶ’      blockIndex < message.blocks.length;
 68вҶ’      blockIndex += 1
 69вҶ’    ) {
 70вҶ’      const block = message.blocks[blockIndex];
 71вҶ’
 72вҶ’      if (!block) {
 73вҶ’        continue;
 74вҶ’      }
 75вҶ’
 76вҶ’      const effects = activeRules
 77вҶ’        .filter((rule) =>
 78вҶ’          matchesReaderRule(
 79вҶ’            rule,
 80вҶ’            message.id,
 81вҶ’            blockIndex,
 82вҶ’            block.type,
 83вҶ’            blockToPlainText(block),
 84вҶ’            context,
 85вҶ’          ),
 86вҶ’        )
 87вҶ’        .map((rule) => rule.compiledRule)
 88вҶ’        .filter((effect): effect is RuleEffect => effect !== undefined)
 89вҶ’        .map(normalizeLegacyEffect);
 90вҶ’
 91вҶ’      if (effects.length > 0) {
 92вҶ’        effectsMap.set(`${message.id}:${blockIndex}`, effects);
 93вҶ’      }
 94вҶ’    }
 95вҶ’  }
 96вҶ’
 97вҶ’  return effectsMap;
 98вҶ’}
