 26вҶ’      const body = message.blocks
 27вҶ’        .map((block) => {
 28вҶ’          switch (block.type) {
 29вҶ’            case "paragraph":
 30вҶ’              return block.text;
 31вҶ’            case "heading":
 32вҶ’              return `${"#".repeat(block.level)} ${block.text}`;
 33вҶ’            case "list":
 34вҶ’              return block.items
 35вҶ’                .map((item, index) =>
 36вҶ’                  block.ordered ? `${index + 1}. ${item}` : `- ${item}`,
 37вҶ’                )
