 46вҶ’            case "table": {
 47вҶ’              const header = `| ${block.headers.map(escapePipe).join(" | ")} |`;
 48вҶ’              const divider = `| ${block.headers.map(() => "---").join(" | ")} |`;
 49вҶ’              const rows = block.rows.map(
 50вҶ’                (row) => `| ${row.map(escapePipe).join(" | ")} |`,
 51вҶ’              );
 52вҶ’              return [header, divider, ...rows].join("\n");
 53вҶ’            }
 54вҶ’          }
 55вҶ’        })
