 77вҶ’export class FormatRegistry {
 78вҶ’  private formats = new Map<string, OutputFormatDescriptor>();
 79вҶ’
 80вҶ’  register(format: OutputFormatDescriptor): void {
 81вҶ’    if (this.formats.has(format.id)) {
 82вҶ’      throw new Error(`Format "${format.id}" is already registered.`);
 83вҶ’    }
 84вҶ’    this.formats.set(format.id, format);
 85вҶ’  }
 86вҶ’
 87вҶ’  get(id: string): OutputFormatDescriptor | undefined {
 88вҶ’    return this.formats.get(id);
 89вҶ’  }
 90вҶ’
 91вҶ’  getAll(): OutputFormatDescriptor[] {
 92вҶ’    return [...this.formats.values()];
 93вҶ’  }
 94вҶ’
 95вҶ’  getAdjustable(): OutputFormatDescriptor[] {
 96вҶ’    return this.getAll().filter((f) => f.adjustable);
 97вҶ’  }
 98вҶ’
 99вҶ’  supportsRuleKind(formatId: string, ruleKind: string): boolean {
100вҶ’    const format = this.formats.get(formatId);
101вҶ’    if (!format) return false;
102вҶ’    return format.supportedRuleKinds.includes(ruleKind);
103вҶ’  }
104вҶ’}
