100вҶ’export function applyMarkdownRules(content: string, rules: FormatRule[]) {
101вҶ’  const lines = content.split("\n");
102вҶ’  const nextLines = [...lines];
103вҶ’
104вҶ’  for (const rule of rules) {
105вҶ’    if (rule.status !== "active") {
106вҶ’      continue;
107вҶ’    }
108вҶ’
109вҶ’    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
110вҶ’    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
111вҶ’
112вҶ’    if (!parsedSelector.success || !parsedEffect.success) {
113вҶ’      continue;
114вҶ’    }
115вҶ’
116вҶ’    const selector = parsedSelector.data;
117вҶ’    const effect = normalizeLegacyEffect(parsedEffect.data);
118вҶ’
119вҶ’    const strategy = "strategy" in selector ? selector.strategy : undefined;
120вҶ’
121вҶ’    if (strategy === "compound") {
122вҶ’      const transform = effect.markdownTransform;
123вҶ’      if (!transform) continue;
124вҶ’
125вҶ’      // Compound in Markdown: textPattern match on each line
126вҶ’      // blockType/messageRole/context not relevant for Markdown (line-based only)
127вҶ’      const textPattern =
128вҶ’        "textPattern" in selector ? selector.textPattern : null;
129вҶ’
130вҶ’      for (let index = 0; index < nextLines.length; index += 1) {
131вҶ’        const line = nextLines[index] ?? "";
132вҶ’
133вҶ’        // If textPattern set: only transform matching lines
134вҶ’        if (textPattern) {
135вҶ’          try {
136вҶ’            if (!new RegExp(textPattern).test(line)) continue;
137вҶ’          } catch {
138вҶ’            continue;
139вҶ’          }
140вҶ’        }
141вҶ’
142вҶ’        // Apply transform (same switch logic as for exact)
143вҶ’        switch (transform) {
144вҶ’          case "promote_to_heading":
145вҶ’            nextLines[index] = `## ${line.replace(/^#+\s*/, "")}`.trimEnd();
146вҶ’            break;
147вҶ’          case "bold_prefix_before_colon":
148вҶ’            nextLines[index] = line.replace(
149вҶ’              /^([^:\n]{1,120}:)(?!\*)/,
150вҶ’              "**$1**",
151вҶ’            );
152вҶ’            break;
153вҶ’          case "normalize_list_structure": {
154вҶ’            const trimmedLine = line.trim();
155вҶ’            if (!trimmedLine) break;
156вҶ’            nextLines[index] = /^[-*]\s/.test(trimmedLine)
157вҶ’              ? trimmedLine
158вҶ’              : `- ${trimmedLine}`;
159вҶ’            break;
160вҶ’          }
161вҶ’          case "normalize_markdown_table":
162вҶ’            if (line.includes("|")) {
163вҶ’              nextLines[index] = line
164вҶ’                .split("|")
165вҶ’                .map((cell) => cell.trim())
166вҶ’                .join(" | ")
167вҶ’                .trim();
168вҶ’            }
169вҶ’            break;
170вҶ’          case "reshape_markdown_block":
171вҶ’            nextLines[index] = line.trimEnd();
172вҶ’            break;
173вҶ’        }
174вҶ’      }
175вҶ’      continue;
176вҶ’    }
177вҶ’
178вҶ’    // All effects are now custom_style after normalization
179вҶ’    {
180вҶ’      const transform = effect.markdownTransform;
181вҶ’      if (!transform) continue;
182вҶ’
183вҶ’      if (
184вҶ’        strategy === "prefix_before_colon" &&
185вҶ’        transform === "bold_prefix_before_colon"
186вҶ’      ) {
187вҶ’        for (let index = 0; index < nextLines.length; index += 1) {
188вҶ’          const line = nextLines[index] ?? "";
189вҶ’          nextLines[index] = line.replace(/^([^:\n]{1,120}:)(?!\*)/, "**$1**");
190вҶ’        }
191вҶ’        continue;
192вҶ’      }
193вҶ’
194вҶ’      if (
195вҶ’        strategy === "markdown_table" &&
196вҶ’        transform === "normalize_markdown_table"
197вҶ’      ) {
198вҶ’        for (let index = 0; index < nextLines.length; index += 1) {
199вҶ’          const line = nextLines[index] ?? "";
200вҶ’          if (!line.includes("|")) continue;
201вҶ’          nextLines[index] = line
202вҶ’            .split("|")
203вҶ’            .map((cell) => cell.trim())
204вҶ’            .join(" | ")
205вҶ’            .trim();
206вҶ’        }
207вҶ’        continue;
208вҶ’      }
209вҶ’
210вҶ’      const lineStart = "lineStart" in selector ? selector.lineStart : null;
211вҶ’      const lineEnd = "lineEnd" in selector ? selector.lineEnd : lineStart;
212вҶ’      if (!lineStart || !lineEnd) continue;
213вҶ’      const startIndex = Math.max(0, lineStart - 1);
214вҶ’      const endIndex = Math.min(nextLines.length - 1, lineEnd - 1);
215вҶ’
216вҶ’      switch (transform) {
217вҶ’        case "promote_to_heading":
218вҶ’          nextLines[startIndex] =
219вҶ’            `## ${nextLines[startIndex]?.replace(/^#+\s*/, "") ?? ""}`.trimEnd();
220вҶ’          break;
221вҶ’        case "bold_prefix_before_colon":
222вҶ’          for (let index = startIndex; index <= endIndex; index += 1) {
223вҶ’            const line = nextLines[index] ?? "";
224вҶ’            nextLines[index] = line.replace(
225вҶ’              /^([^:\n]{1,120}:)(?!\*)/,
226вҶ’              "**$1**",
227вҶ’            );
228вҶ’          }
229вҶ’          break;
230вҶ’        case "normalize_list_structure":
231вҶ’          for (let index = startIndex; index <= endIndex; index += 1) {
232вҶ’            const line = nextLines[index] ?? "";
233вҶ’            const trimmedLine = line.trim();
234вҶ’            if (!trimmedLine) continue;
235вҶ’            nextLines[index] = /^[-*]\s/.test(trimmedLine)
236вҶ’              ? trimmedLine
237вҶ’              : `- ${trimmedLine}`;
238вҶ’          }
239вҶ’          break;
240вҶ’        case "normalize_markdown_table":
241вҶ’          for (let index = startIndex; index <= endIndex; index += 1) {
242вҶ’            const line = nextLines[index] ?? "";
243вҶ’            nextLines[index] = line
244вҶ’              .split("|")
245вҶ’              .map((cell) => cell.trim())
246вҶ’              .join(" | ")
247вҶ’              .trim();
248вҶ’          }
249вҶ’          break;
250вҶ’        case "reshape_markdown_block":
251вҶ’          for (let index = startIndex; index <= endIndex; index += 1) {
252вҶ’            nextLines[index] = (nextLines[index] ?? "").trimEnd();
253вҶ’          }
254вҶ’          break;
255вҶ’      }
256вҶ’    }
257вҶ’  }
258вҶ’
259вҶ’  return nextLines.join("\n");
260вҶ’}
